// Hardcode sources
const sources = [
  {
    name: 'VnExpress',
    url: 'https://vnexpress.net/rss/tin-moi-nhat.rss',
    category: 'Tin tức tổng hợp'
  },
  {
    name: 'VnExpress - Công nghệ',
    url: 'https://vnexpress.net/rss/so-hoa.rss',
    category: 'Công nghệ'
  },
  {
    name: 'VnExpress - Kinh doanh',
    url: 'https://vnexpress.net/rss/kinh-doanh.rss',
    category: 'Kinh tế'
  }
];

return sources.map(source => ({ json: source }));

const sourceName = $input.first().json.name || 'Unknown';
const sourceCategory = $input.first().json.category || 'Khác';

const rss = $input.first().json.rss?.channel?.[0];

if (!rss || !rss.item) {
  return [];
}

const articles = rss.item.slice(0, 10);

const results = articles.map((article, index) => {
  const title = Array.isArray(article.title) ? article.title[0] : article.title;
  const link = Array.isArray(article.link) ? article.link[0] : article.link;
  const description = Array.isArray(article.description) ? article.description[0] : article.description;
  const pubDate = Array.isArray(article.pubDate) ? article.pubDate[0] : article.pubDate;

  return {
    json: {
      id: `${sourceName.toLowerCase().replace(/\s+/g, '-')}-${Date.now()}-${index}`,
      title: title || '',
      link: link || '',
      description: (description || '').replace(/<[^>]*>/g, '').substring(0, 200),
      source: sourceName,
      category: sourceCategory,
      pubDate: new Date(pubDate).toLocaleString('vi-VN', {
        timeZone: 'Asia/Ho_Chi_Minh',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      }),
      collectedAt: new Date().toLocaleString('vi-VN', {
        timeZone: 'Asia/Ho_Chi_Minh',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    }
  };
});

return results;

const includeKeywords = ['ai', 'trí tuệ nhân tạo', 'công nghệ', 'startup', 'đầu tư', 'kinh tế', 'chứng khoán', 'bitcoin', 'blockchain', 'khoa học', 'công ty'];
const excludeKeywords = ['tai nạn', 'tử vong', 'bạo lực'];

const filtered = $input.all().filter(item => {
  const text = (item.json.title + ' ' + item.json.description).toLowerCase();

  const hasExclude = excludeKeywords.some(keyword => text.includes(keyword.toLowerCase()));
  if (hasExclude) return false;

  const hasInclude = includeKeywords.some(keyword => text.includes(keyword.toLowerCase()));
  return hasInclude;
});

return filtered;
